/// Promo module configuration
///
/// Use the builder pattern to configure and register this module:
///
/// ```text
/// let promo = PromoModule::builder()
///     .with_database(pool.clone())
///     .build()?;
///
/// let router = promo.routes();
/// ```
pub struct PromoModule {
    pub ad_performance_service: Arc<AdPerformanceService>,
    pub advertisement_service: Arc<AdvertisementService>,
    pub provider_promo_service: Arc<ProviderPromoService>,
    pub promo_campaign_service: Arc<PromoCampaignService>,
}

impl PromoModule {
    /// Create a new module builder
    pub fn builder() -> PromoModuleBuilder {
        PromoModuleBuilder::new()
    }

    /// Configure HTTP routes for this module using Axum
    ///
    /// Returns an Axum Router with all 12 Backbone CRUD endpoints per entity.
    pub fn routes(&self) -> Router {
        use presentation::http::{
            create_ad_performance_routes,
            create_advertisement_routes,
            create_provider_promo_routes,
            create_promo_campaign_routes,
        };

        Router::new()
            .merge(create_ad_performance_routes(self.ad_performance_service.clone()))
            .merge(create_advertisement_routes(self.advertisement_service.clone()))
            .merge(create_provider_promo_routes(self.provider_promo_service.clone()))
            .merge(create_promo_campaign_routes(self.promo_campaign_service.clone()))
    }
}

/// Builder for PromoModule
pub struct PromoModuleBuilder {
    db_pool: Option<PgPool>,
}

impl PromoModuleBuilder {
    /// Create a new builder
    pub fn new() -> Self {
        Self {
            db_pool: None,
        }
    }

    /// Set the database connection pool
    pub fn with_database(mut self, pool: PgPool) -> Self {
        self.db_pool = Some(pool);
        self
    }

    /// Build the module with configured dependencies
    pub fn build(self) -> anyhow::Result<PromoModule> {
        let db_pool = self.db_pool
            .ok_or_else(|| anyhow::anyhow!("Database pool not configured"))?;

        // AdPerformance service
        let ad_performance_repository = Arc::new(AdPerformanceRepository::new(db_pool.clone()));
        let ad_performance_service = Arc::new(AdPerformanceService::with_repository(ad_performance_repository.clone()));

        // Advertisement service
        let advertisement_repository = Arc::new(AdvertisementRepository::new(db_pool.clone()));
        let advertisement_service = Arc::new(AdvertisementService::with_repository(advertisement_repository.clone()));

        // ProviderPromo service
        let provider_promo_repository = Arc::new(ProviderPromoRepository::new(db_pool.clone()));
        let provider_promo_service = Arc::new(ProviderPromoService::with_repository(provider_promo_repository.clone()));

        // PromoCampaign service
        let promo_campaign_repository = Arc::new(PromoCampaignRepository::new(db_pool.clone()));
        let promo_campaign_service = Arc::new(PromoCampaignService::with_repository(promo_campaign_repository.clone()));

        // <<< CUSTOM
        // END CUSTOM

        Ok(PromoModule {
            ad_performance_service,
            advertisement_service,
            provider_promo_service,
            promo_campaign_service,
            // <<< CUSTOM
            // END CUSTOM
        })
    }
}

